import{_ as a,I as p,o as r,c as s,at as _,J as t}from"./chunks/framework.DYZFTu11.js";const f=JSON.parse('{"title":"《第二章：阴影中的回响》","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/novels/liehenzhihuo/chapter-03.md","filePath":"zh_cn/novels/liehenzhihuo/chapter-03.md","lastUpdated":1773498699000}'),c={name:"zh_cn/novels/liehenzhihuo/chapter-03.md"};function i(l,e,h,d,g,m){const o=p("NolebaseGitContributors"),n=p("NolebaseGitChangelog");return r(),s("div",null,[e[0]||(e[0]=_('<h1 id="《第二章-阴影中的回响》" tabindex="-1"><strong>《第二章：阴影中的回响》</strong> <a class="header-anchor" href="#《第二章-阴影中的回响》" aria-label="Permalink to “《第二章：阴影中的回响》”">​</a></h1><p><strong>《第二章：阴影中的回响》</strong></p><p><strong>β星时间 2059年8月1日 03:45</strong><strong>第二街区，地下数据黑市“蜂巢”</strong></p><p>半个月后。</p><p>夜隼，或者说“零”，再次出现在了第三街区。</p><p>这里已经变成了一片巨大的工地，财团的工程机器人正在效率惊人地清理着“废墟”，为即将拔地而起的豪华公寓打下地基。空气中弥漫着金属切割的焦糊味和消毒水的刺鼻气味，曾经那些鲜活的、充满了市井气息的痕迹，被抹除得一干二净。</p><p>零就像一个真正的幽灵，悄无声息地穿行在这片“新生”的土地上。他从被拆毁的书店地下室里，挖出了自己藏在那里的、最重要的“宝贝”——一个经过物理隔绝的、储存着他所有工具和“战利品”的服务器。</p><p>然后，他来到了“蜂巢”。</p><p>“蜂巢”是β星最大的地下数据黑市，一个由废弃的地铁枢纽改造而成的、不见天日的迷宫。这里是信息掮客、黑客、以及各种游走在灰色地带的人们的天堂。财团的秩序在这里荡然无存，取而代之的，是另一套由实力和信誉构筑的、更古老的丛林法则。</p><p>零的目标很明确，他要找一个人——代号“铁匠”的硬件专家。</p><p>在“蜂巢”里，没人知道“铁匠”的真名，也没人见过他的真面目。人们只知道，他能将任何你能想象到的电子垃圾，改装成致命的武器或者精密的工具。无论是能让财团最新款监控探头集体“失明”的电磁脉冲装置，还是能破解军用级加密频道的信号拦截器，只要你出得起价钱，他都能给你造出来。</p><p>零穿过嘈杂混乱的交易大厅，熟练地绕开几个角落里正在进行的可疑交易，走进了一条不起眼的维修通道。在通道的尽头，一扇毫不起眼的、布满了涂鸦的金属门后，就是“铁匠”的工坊。</p><p>他按照黑市的规矩，用指节，在门上敲出了一个由三长两短组成的、不规则的密码。</p><p>金属门后传来一阵齿轮转动的声音，一道小小的观察窗被打开，一双隐藏在护目镜后的、无比警惕的眼睛，在黑暗中审视着他。</p><p>“我需要一些‘玩具’。”零压低了声音，兜帽的阴影遮住了他的脸，“能让财团的‘走狗’们，尝尝厉害的玩具。”</p><p>观察窗后的那双眼睛，似乎是辨认出了他的声音。</p><p>“‘零’？你还活着？”一个沙哑的、像是被砂纸打磨过的女声响起，带着一丝不易察-觉的惊讶，“我以为你和第三街区那堆废铁一起，被‘净化’掉了。”</p><p>“差一点。”零的声音里听不出任何情绪，“开门吧，‘铁匠’。我这次的订单，你一定会感兴趣。”</p><p>厚重的金属门缓缓开启，一股浓烈的机油和金属焊-接的气味扑面而来。</p><p>门的背后，一个身材娇小的、穿着满是油污的工装服的女人，正斜倚在工作台上。她有着一头火红色的短发，脸上还带着几道机油的污渍，但那双眼睛，却像黑曜石一样明亮而锐利。</p><p>她就是“蜂巢”里传说中的“铁匠”。</p><p>也是零的第一个目标。</p><p>因为他知道，“铁匠”和财团之间，同样有着一笔血债。</p>',23)),t(o),t(n)])}const b=a(c,[["render",i]]);export{f as __pageData,b as default};
